//-------------------------------------------------------------------------
// 코드와 Hidden 값이 같은 지 여부를 반환
//-------------------------------------------------------------------------
scwin.f_CheckHidVal = async function (inObj) {
  if (scwin.f_IsArray(inObj)) {
    for (let i = 0; i < inObj.length; i++) {
      if (scwin.f_CheckHidVal(inObj[i]) == false) return false;
    }
  } else {
    let objName = inObj.options.validExp.split(":")[0];
    if ($c.gus.cfIsNull($p, $c.gus.cfGetValue($p, inObj))) return true;
    if ((await $c.gus.cfGetValue($p, inObj)) != $c.gus.cfGetHiddenValue($p, inObj)) {
      await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_038, $c.gus.cfIsNull($p, objName) ? "코드" : objName));
      inObj.focus();
      return false;
    }
  }
  return true;
};

